/* ---------- assinatura: três barras ---------- */
function Bars({ className = "" }) {
  return (
    <span className={"ryz-bars " + className} aria-hidden="true">
      <i></i>
      <i></i>
      <i></i>
    </span>
  );
}

/* ---------- eyebrow (barras + label) ---------- */
function Eyebrow({ label }) {
  return (
    <span className="ryz-eyebrow">
      <Bars className="eb" />
      {label}
    </span>
  );
}

/* ---------- revelar ao rolar (fade + blur) ---------- */
function useReveal() {
  const ref = useRef(null);
  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const io = new IntersectionObserver(
      (entries) => {
        entries.forEach((e) => {
          if (e.isIntersecting) {
            e.target.classList.add("in");
            io.unobserve(e.target);
          }
        });
      },
      { threshold: 0.14, rootMargin: "0px 0px -8% 0px" }
    );
    el.querySelectorAll(".reveal").forEach((n) => io.observe(n));
    return () => io.disconnect();
  }, []);
  return ref;
}

/* ---------- parallax extremamente leve (desktop) ---------- */
function useParallax() {
  const ref = useRef(null);
  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const reduce = window.matchMedia("(prefers-reduced-motion: reduce)").matches;
    if (reduce || window.innerWidth < 960) return;
    let raf = 0;
    const onMove = (ev) => {
      const r = el.getBoundingClientRect();
      const dx = (ev.clientX - (r.left + r.width / 2)) / r.width;
      const dy = (ev.clientY - (r.top + r.height / 2)) / r.height;
      cancelAnimationFrame(raf);
      raf = requestAnimationFrame(() => {
        el.style.setProperty("--px", (dx * 9).toFixed(2) + "px");
        el.style.setProperty("--py", (dy * 9).toFixed(2) + "px");
        el.style.setProperty("--rx", (-dy * 2).toFixed(2) + "deg");
        el.style.setProperty("--ry", (dx * 3).toFixed(2) + "deg");
      });
    };
    window.addEventListener("mousemove", onMove);
    return () => {
      window.removeEventListener("mousemove", onMove);
      cancelAnimationFrame(raf);
    };
  }, []);
  return ref;
}

