/* =========================================================== */
const CSS = `
@import url('https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@400;500;600;700&family=Inter:wght@400;500&family=JetBrains+Mono:wght@400;500&display=swap');

.ryz-root{
  --bg:#050505; --bg2:#0e0e0e; --panel:#121212;
  --green:#BCE01A;            /* verde oficial extraído das barras */
  --green-rgb:188,224,26;
  --white:#FFFFFF; --muted:#B5B5B5; --dim:#6f6f6f;
  --line:rgba(255,255,255,.08);
  --glass:rgba(255,255,255,.022);
  position:relative; background:var(--bg); color:var(--white);
  font-family:'Inter',system-ui,sans-serif; overflow-x:hidden;
  -webkit-font-smoothing:antialiased; letter-spacing:.005em;
}
.ryz-root *{box-sizing:border-box;}
.ryz-root a{color:inherit;text-decoration:none;cursor:pointer;}
.mono{font-family:'JetBrains Mono',monospace;}
.ryz-container{width:100%;max-width:1200px;margin:0 auto;padding:0 clamp(22px,5vw,48px);}

h1,h2,h3{font-family:'Space Grotesk',sans-serif;margin:0;font-weight:600;}
.ryz-em{color:var(--white);}
.ryz-h1 .ryz-em{background:linear-gradient(180deg,#fff,#cfcfcf);-webkit-background-clip:text;background-clip:text;color:transparent;}

/* ===== assinatura: três barras ===== */
.ryz-bars{display:inline-flex;flex-direction:column;gap:3px;flex-shrink:0;}
.ryz-bars i{display:block;width:17px;height:2px;border-radius:2px;background:var(--green);}
.ryz-bars.eb i{width:14px;gap:2px;}
.ryz-bars.eb{gap:2.5px;}

/* ---- atmosfera ---- */
.ryz-atmo{position:fixed;inset:0;z-index:0;pointer-events:none;}
.ryz-light{position:absolute;top:-22%;left:50%;transform:translateX(-50%);width:1100px;height:760px;border-radius:50%;background:radial-gradient(ellipse at center,rgba(255,255,255,.05),transparent 62%);filter:blur(20px);}
.ryz-grid{position:absolute;inset:0;background-image:linear-gradient(var(--line) 1px,transparent 1px),linear-gradient(90deg,var(--line) 1px,transparent 1px);background-size:96px 96px;opacity:.14;-webkit-mask-image:radial-gradient(ellipse at 50% 12%,#000,transparent 70%);mask-image:radial-gradient(ellipse at 50% 12%,#000,transparent 70%);}
.ryz-vignette{position:absolute;inset:0;background:radial-gradient(ellipse at 50% 38%,transparent 52%,rgba(0,0,0,.55) 100%);}

/* ---- nav ---- */
.ryz-nav{position:fixed;top:0;left:0;right:0;z-index:50;transition:background .4s,border-color .4s,backdrop-filter .4s;border-bottom:1px solid transparent;}
.ryz-nav.is-scrolled{background:rgba(5,5,5,.66);backdrop-filter:blur(16px) saturate(120%);border-bottom:1px solid var(--line);}
.ryz-nav-in{display:flex;align-items:center;gap:26px;height:78px;}
.ryz-brand{display:flex;align-items:center;gap:12px;margin-right:auto;}
.ryz-brand-mark{width:34px;height:34px;border-radius:50%;object-fit:cover;}
.ryz-brand-word{font-family:'Space Grotesk',sans-serif;font-weight:600;font-size:18px;letter-spacing:.24em;}
.ryz-links{display:flex;gap:36px;}
.ryz-links a{font-size:14px;color:var(--muted);transition:color .25s;position:relative;}
.ryz-links a:hover{color:var(--white);}
.ryz-links a::after{content:"";position:absolute;left:0;bottom:-7px;width:0;height:1px;background:var(--green);transition:width .3s ease;}
.ryz-links a:hover::after{width:100%;}
.ryz-nav-cta{padding:10px 18px;font-size:13px;}
.ryz-burger{display:none;background:none;border:none;color:var(--white);cursor:pointer;padding:6px;}
.ryz-mobile{display:none;flex-direction:column;gap:2px;padding:14px clamp(22px,5vw,48px) 24px;background:rgba(5,5,5,.96);border-bottom:1px solid var(--line);backdrop-filter:blur(16px);}
.ryz-mobile a{padding:15px 2px;color:var(--muted);font-size:15px;border-bottom:1px solid var(--line);}
.ryz-mobile a:nth-last-child(1){border:none;margin-top:12px;justify-content:center;}

/* ---- botões ---- */
.ryz-btn{display:inline-flex;align-items:center;justify-content:center;gap:9px;border-radius:11px;font-weight:500;font-size:14px;border:1px solid transparent;cursor:pointer;transition:background .35s ease,color .35s ease,border-color .35s ease,transform .35s ease;font-family:'Inter',sans-serif;}
.ryz-btn-lg{padding:15px 24px;font-size:14.5px;border-radius:12px;}
.ryz-btn-primary{background:var(--panel);color:var(--white);border-color:rgba(var(--green-rgb),.45);}
.ryz-btn-primary:hover{background:var(--green);color:#0c1300;border-color:var(--green);}
.ryz-btn-primary svg{transition:transform .35s ease;}
.ryz-btn-primary:hover svg{transform:translate(2px,-2px);}
.ryz-btn-ghost{background:transparent;color:var(--white);border-color:var(--line);}
.ryz-btn-ghost:hover{border-color:rgba(255,255,255,.32);}
.ryz-btn-ghost svg{transition:transform .35s ease;}
.ryz-btn-ghost:hover svg{transform:translateX(3px);}

/* ---- eyebrow ---- */
.ryz-eyebrow{display:inline-flex;align-items:center;gap:13px;font-size:11.5px;letter-spacing:.26em;text-transform:uppercase;color:var(--dim);font-weight:500;}

/* ---- hero ---- */
.ryz-hero{position:relative;z-index:1;min-height:100vh;display:flex;align-items:center;padding:120px 0 80px;}
.ryz-hero-in{display:grid;grid-template-columns:1.05fr .95fr;gap:clamp(40px,6vw,88px);align-items:center;width:100%;}
.ryz-hero-copy{max-width:560px;}
.ryz-h1{font-size:clamp(48px,7.6vw,90px);line-height:.95;font-weight:600;letter-spacing:-.03em;}
.ryz-sub{color:var(--muted);font-size:clamp(16px,1.5vw,18.5px);line-height:1.6;margin:32px 0 0;max-width:420px;}
.ryz-hero-actions{display:flex;flex-wrap:wrap;gap:13px;margin-top:44px;}
.ryz-hero-meta{display:flex;align-items:center;gap:13px;margin-top:56px;color:var(--dim);font-size:11.5px;letter-spacing:.2em;text-transform:uppercase;}
.ryz-hero-meta em{font-style:normal;color:rgba(var(--green-rgb),.6);}
.ryz-bars.meta-bars i{width:12px;}

/* ---- composição de branding ---- */
.ryz-comp{position:relative;display:flex;align-items:center;justify-content:center;min-height:440px;perspective:1200px;--px:0px;--py:0px;--rx:0deg;--ry:0deg;}
.herologo-light{position:absolute;width:min(480px,88%);aspect-ratio:1;border-radius:50%;background:radial-gradient(circle,rgba(255,255,255,.05),transparent 62%);filter:blur(22px);}
.herologo-img{position:relative;z-index:1;width:min(430px,82%);display:block;transform:translate(var(--px),var(--py));transition:transform .25s ease-out;filter:drop-shadow(0 30px 60px rgba(0,0,0,.6));}
.comp-back{position:absolute;width:80%;height:78%;top:4%;right:4%;border-radius:22px;border:1px solid var(--line);background:linear-gradient(160deg,rgba(255,255,255,.03),transparent);transform:translate(calc(var(--px)*-1.3),calc(var(--py)*-1.3)) rotate(-2deg);box-shadow:0 50px 90px -55px rgba(0,0,0,.95);}
.comp-card{position:relative;z-index:2;margin:0;width:86%;max-width:430px;padding:34px 34px 28px;border-radius:22px;border:1px solid rgba(255,255,255,.1);background:linear-gradient(165deg,rgba(22,23,24,.9),rgba(8,8,9,.92));backdrop-filter:blur(10px);box-shadow:0 60px 110px -55px rgba(0,0,0,.95),inset 0 1px 0 rgba(255,255,255,.05);transform:translate(var(--px),var(--py)) rotateX(var(--rx)) rotateY(var(--ry));transition:transform .25s ease-out;transform-style:preserve-3d;overflow:hidden;}
.comp-card::before{content:"";position:absolute;top:-40%;left:-10%;width:120%;height:80%;background:radial-gradient(ellipse at center,rgba(255,255,255,.06),transparent 60%);pointer-events:none;}
.comp-head{display:flex;align-items:center;justify-content:flex-end;position:relative;}
.ryz-bars.comp-mark i{width:20px;height:2px;}
.comp-reg{font-size:10.5px;letter-spacing:.2em;color:var(--dim);text-transform:uppercase;}
.comp-name{display:flex;align-items:flex-end;gap:14px;margin:34px 0 30px;position:relative;}
.comp-word{font-family:'Space Grotesk',sans-serif;font-weight:600;font-size:clamp(40px,6vw,58px);letter-spacing:.04em;line-height:.9;background:linear-gradient(180deg,#fff,#bdbdbd);-webkit-background-clip:text;background-clip:text;color:transparent;}
.ryz-bars.comp-bars-lg{gap:4px;margin-bottom:9px;}
.ryz-bars.comp-bars-lg i{width:26px;height:3px;}
.comp-list{list-style:none;margin:0;padding:26px 0;border-top:1px solid var(--line);border-bottom:1px solid var(--line);display:flex;flex-direction:column;gap:16px;position:relative;}
.comp-list li{display:flex;align-items:center;gap:14px;font-family:'Space Grotesk',sans-serif;font-size:16px;color:var(--muted);}
.comp-list li .mono{font-size:11px;color:var(--dim);min-width:18px;}
.comp-list li span:nth-child(2){flex:1;}
.ryz-bars.comp-li{flex-direction:row;gap:3px;opacity:.35;transition:opacity .4s;}
.ryz-bars.comp-li i{width:6px;height:6px;border-radius:1px;}
.comp-list li:hover .comp-li{opacity:1;}
.comp-list li:hover{color:var(--white);}
.comp-foot{display:flex;align-items:center;justify-content:space-between;margin-top:24px;color:var(--dim);font-size:11px;letter-spacing:.14em;text-transform:uppercase;position:relative;}
.comp-foot svg{color:var(--green);}
.comp-side{position:absolute;top:50%;right:-2px;transform:translateY(-50%) rotate(90deg);transform-origin:right center;font-size:9.5px;letter-spacing:.42em;color:rgba(255,255,255,.16);text-transform:uppercase;}

/* ---- entrada hero ---- */
.ryz-anim{opacity:0;transform:translateY(18px);filter:blur(6px);animation:heroIn .9s cubic-bezier(.2,.7,.2,1) forwards;}
.a1{animation-delay:.06s}.a2{animation-delay:.2s}.a3{animation-delay:.34s}.a4{animation-delay:.48s}
@keyframes heroIn{to{opacity:1;transform:none;filter:none;}}

/* ---- seções ---- */
.ryz-sec{position:relative;z-index:1;padding:clamp(96px,15vh,168px) 0;}
.ryz-sec-head{max-width:680px;margin:0 auto clamp(56px,7vw,84px);text-align:center;display:flex;flex-direction:column;align-items:center;gap:22px;}
.ryz-h2{font-size:clamp(30px,4.4vw,52px);line-height:1.04;letter-spacing:-.025em;}
.ryz-p{color:var(--muted);font-size:16.5px;line-height:1.75;margin:0;}
.ryz-p+.ryz-p{margin-top:18px;}
.ryz-p-lead{max-width:520px;font-size:16px;}

/* ---- cards base ---- */
.card{position:relative;background:var(--glass);backdrop-filter:blur(12px);border:1px solid var(--line);border-radius:20px;transition:transform .45s cubic-bezier(.2,.7,.2,1),border-color .45s,box-shadow .45s;box-shadow:inset 0 1px 0 rgba(255,255,255,.03),0 30px 60px -50px rgba(0,0,0,.9);}
.card:hover{transform:translateY(-6px);border-color:rgba(255,255,255,.16);box-shadow:inset 0 1px 0 rgba(255,255,255,.05),0 40px 70px -45px rgba(0,0,0,.95);}

/* ---- serviços ---- */
.serv-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:clamp(16px,1.6vw,22px);}
.serv-card{padding:clamp(28px,3vw,40px);overflow:hidden;}
.serv-corner{position:absolute;top:22px;right:24px;gap:2.5px;opacity:.45;transition:opacity .4s;}
.serv-corner i{width:13px;}
.serv-card:hover .serv-corner{opacity:1;}
.serv-icon{width:50px;height:50px;border-radius:13px;display:flex;align-items:center;justify-content:center;background:rgba(255,255,255,.03);color:var(--muted);border:1px solid var(--line);margin-bottom:24px;transition:color .4s,border-color .4s;}
.serv-card:hover .serv-icon{color:var(--green);border-color:rgba(var(--green-rgb),.3);}
.serv-title{font-size:21px;margin-bottom:14px;letter-spacing:-.01em;}
.serv-text{color:var(--muted);font-size:14.5px;line-height:1.7;margin:0 0 22px;}
.serv-link{display:inline-flex;align-items:center;gap:7px;color:var(--dim);font-size:13px;font-weight:500;letter-spacing:.04em;transition:color .3s,gap .3s;}
.serv-card:hover .serv-link{color:var(--green);}
.serv-link:hover{gap:11px;}

/* ---- quem somos ---- */
.quem-grid{display:grid;grid-template-columns:1fr 1fr;gap:clamp(40px,6vw,80px);align-items:center;}
.quem-text{display:flex;flex-direction:column;gap:24px;}
.quem-text .ryz-h2{margin-top:2px;}
.quem-text .ryz-p{max-width:480px;}
.quem-media{position:relative;}
.quem-back{position:absolute;top:-22px;left:-22px;width:62%;height:78%;border:1px solid var(--line);border-radius:18px;background:linear-gradient(160deg,rgba(255,255,255,.03),transparent);}
.quem-frame{position:relative;margin:0;border:1px solid var(--line);border-radius:18px;overflow:hidden;background:#0a0a0a;box-shadow:0 50px 90px -55px rgba(0,0,0,.9);}
.quem-frame img{display:block;width:100%;height:auto;filter:contrast(1.05) brightness(.94) saturate(.92);}
.quem-overlay{position:absolute;inset:0;background:linear-gradient(180deg,transparent 40%,rgba(5,5,5,.55) 100%),radial-gradient(120% 80% at 80% 10%,transparent 60%,rgba(5,5,5,.4));}
.quem-corner{position:absolute;left:18px;bottom:18px;width:34px;height:34px;border-left:1px solid var(--green);border-bottom:1px solid var(--green);opacity:.6;}

/* ---- processo (barras como evolução, sem linha) ---- */
.proc-line{display:grid;grid-template-columns:repeat(5,1fr);gap:clamp(20px,2.4vw,34px);}
.proc-step{position:relative;}
.ryz-bars.proc-bars{flex-direction:row;gap:4px;margin-bottom:20px;}
.ryz-bars.proc-bars i{width:14px;height:3px;background:rgba(255,255,255,.14);transition:background .6s ease;}
.proc-step.in .proc-bars i:nth-child(1){background:var(--green);transition-delay:.05s;}
.proc-step.in .proc-bars i:nth-child(2){background:var(--green);transition-delay:.22s;}
.proc-step.in .proc-bars i:nth-child(3){background:var(--green);transition-delay:.39s;}
.proc-num{font-size:12.5px;color:var(--dim);letter-spacing:.06em;display:block;margin-bottom:10px;}
.proc-title{font-size:19px;margin:0 0 9px;letter-spacing:-.01em;}
.proc-text{color:var(--muted);font-size:14px;line-height:1.65;margin:0;padding-right:6px;}

/* ---- portfólio ---- */
.port-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:clamp(16px,1.6vw,22px);}
.port-card{overflow:hidden;}
.port-media{position:relative;aspect-ratio:16/10;overflow:hidden;border-bottom:1px solid var(--line);display:flex;align-items:center;justify-content:center;}
.port-grad{position:absolute;inset:0;background:radial-gradient(120% 100% at 30% 0%,#161718,#0b0b0c 60%,#070707);transition:transform .6s cubic-bezier(.2,.7,.2,1);}
.port-card:hover .port-grad{transform:scale(1.05);}
.ryz-bars.port-bars{position:relative;z-index:1;flex-direction:row;gap:5px;opacity:.5;transition:opacity .4s,gap .4s;}
.ryz-bars.port-bars i{width:18px;height:3px;}
.port-card:hover .port-bars{opacity:1;gap:7px;}
.port-ph{position:absolute;bottom:14px;left:0;right:0;text-align:center;z-index:1;font-size:10.5px;letter-spacing:.18em;text-transform:uppercase;color:rgba(255,255,255,.3);}
.port-info{padding:24px 24px 26px;}
.port-cat{font-size:10.5px;letter-spacing:.18em;text-transform:uppercase;color:var(--dim);font-weight:500;}
.port-name{font-size:19px;margin:11px 0 18px;letter-spacing:-.01em;}
.port-link{display:inline-flex;align-items:center;gap:7px;font-size:13px;font-weight:500;color:var(--muted);letter-spacing:.03em;transition:gap .3s,color .3s;}
.port-link:hover{gap:11px;color:var(--green);}

/* ---- por que (identidade reforçada) ---- */
.porque{overflow:hidden;}
.ryz-bars.porque-watermark{position:absolute;top:14%;right:-30px;z-index:0;flex-direction:column;gap:30px;opacity:.05;}
.ryz-bars.porque-watermark i{width:220px;height:26px;border-radius:5px;}
.porque-grid{position:relative;z-index:1;display:grid;grid-template-columns:repeat(2,1fr);gap:0;border-top:1px solid var(--line);}
.porque-item{position:relative;display:flex;align-items:flex-start;gap:22px;padding:clamp(30px,3.2vw,46px) clamp(20px,2.6vw,44px);border-bottom:1px solid var(--line);transition:background .4s;}
.porque-item:nth-child(odd){border-right:1px solid var(--line);}
.porque-item:hover{background:rgba(255,255,255,.014);}
.ryz-bars.porque-bars{margin-top:6px;gap:3px;}
.ryz-bars.porque-bars i{width:18px;height:2px;background:rgba(255,255,255,.2);transition:background .4s,width .4s;}
.porque-item:hover .porque-bars i{background:var(--green);}
.porque-item:hover .porque-bars i:nth-child(2){width:13px;}
.porque-item:hover .porque-bars i:nth-child(3){width:9px;}
.porque-idx{font-size:12px;color:var(--green);opacity:.55;flex-shrink:0;padding-top:6px;}
.porque-title{font-size:21px;margin-bottom:11px;letter-spacing:-.01em;}
.porque-text{color:var(--muted);font-size:14.5px;line-height:1.7;margin:0;max-width:300px;}

/* ---- faq ---- */
.faq-wrap{display:grid;grid-template-columns:.8fr 1.2fr;gap:clamp(40px,5vw,72px);align-items:start;}
.faq-head{display:flex;flex-direction:column;gap:20px;}
.faq-head .ryz-h2{font-size:clamp(28px,3.4vw,40px);}
.faq-list{display:flex;flex-direction:column;}
.faq-item{border-bottom:1px solid var(--line);}
.faq-item:first-child{border-top:1px solid var(--line);}
.faq-q{width:100%;display:flex;align-items:center;justify-content:space-between;gap:20px;padding:26px 4px;background:none;border:none;color:var(--white);font-family:'Space Grotesk',sans-serif;font-size:17px;font-weight:500;text-align:left;cursor:pointer;transition:color .3s;}
.faq-q-in{display:inline-flex;align-items:center;gap:16px;}
.ryz-bars.faq-bars{gap:2.5px;opacity:.45;transition:opacity .3s;}
.ryz-bars.faq-bars i{width:13px;}
.faq-item.open .faq-bars,.faq-q:hover .faq-bars{opacity:1;}
.faq-q svg{color:var(--green);flex-shrink:0;}
.faq-a{max-height:0;overflow:hidden;transition:max-height .45s ease;}
.faq-item.open .faq-a{max-height:280px;}
.faq-a p{margin:0;padding:0 4px 28px 33px;color:var(--muted);font-size:15px;line-height:1.7;max-width:580px;}

/* ---- cta ---- */
.ryz-cta{position:relative;z-index:1;padding:clamp(90px,12vh,150px) 0;}
.cta-in{position:relative;max-width:820px;margin:0 auto;text-align:center;border:1px solid var(--line);border-radius:28px;padding:clamp(48px,7vw,80px) clamp(28px,5vw,64px);background:linear-gradient(180deg,rgba(255,255,255,.022),rgba(255,255,255,0));overflow:hidden;display:flex;flex-direction:column;align-items:center;}
.cta-light{position:absolute;top:-50%;left:50%;transform:translateX(-50%);width:560px;height:360px;background:radial-gradient(ellipse at center,rgba(255,255,255,.05),transparent 65%);pointer-events:none;}
.ryz-bars.cta-bars{flex-direction:row;gap:5px;margin-bottom:30px;position:relative;}
.ryz-bars.cta-bars i{width:22px;height:3px;}
.cta-title{font-size:clamp(27px,3.6vw,42px);line-height:1.14;position:relative;letter-spacing:-.02em;max-width:660px;}
.cta-sub{color:var(--muted);font-size:18px;margin:20px 0 36px;position:relative;}
.cta-in .ryz-btn{position:relative;}

/* ---- rodapé ---- */
.ryz-footer{position:relative;z-index:1;border-top:1px solid var(--line);padding-top:clamp(56px,7vw,80px);}
.foot-in{display:flex;justify-content:space-between;gap:48px;flex-wrap:wrap;padding-bottom:clamp(44px,5vw,64px);}
.foot-brand{display:flex;align-items:center;gap:15px;}
.foot-mark{width:50px;height:50px;border-radius:50%;}
.foot-brand-txt strong{font-family:'Space Grotesk',sans-serif;font-size:19px;letter-spacing:.2em;display:block;margin-bottom:5px;}
.foot-brand-txt span{color:var(--muted);font-size:14px;}
.foot-cols{display:flex;gap:clamp(40px,6vw,72px);flex-wrap:wrap;}
.foot-label{display:inline-flex;align-items:center;gap:9px;font-size:11px;letter-spacing:.2em;text-transform:uppercase;color:var(--dim);margin-bottom:16px;}
.ryz-bars.foot-bars{gap:2px;}
.ryz-bars.foot-bars i{width:11px;height:1.5px;}
.foot-line{display:flex;align-items:center;gap:9px;color:var(--muted);font-size:14.5px;margin:0 0 12px;transition:color .3s;}
.foot-line svg{color:var(--green);}
.foot-line.link:hover{color:var(--white);}
.foot-bottom{display:flex;justify-content:space-between;gap:16px;flex-wrap:wrap;padding:24px clamp(22px,5vw,48px);border-top:1px solid var(--line);color:var(--dim);font-size:12.5px;}

/* ---- fab ---- */
.ryz-fab{position:fixed;right:24px;bottom:24px;z-index:60;width:54px;height:54px;border-radius:14px;background:var(--panel);color:var(--white);border:1px solid rgba(var(--green-rgb),.4);display:flex;align-items:center;justify-content:center;box-shadow:0 20px 40px -20px rgba(0,0,0,.9);transition:background .35s,color .35s,transform .35s,border-color .35s;}
.ryz-fab:hover{background:var(--green);color:#0c1300;border-color:var(--green);transform:translateY(-3px);}

/* ---- reveal ---- */
.reveal{opacity:0;transform:translateY(22px);filter:blur(7px);transition:opacity .8s cubic-bezier(.2,.7,.2,1),transform .8s cubic-bezier(.2,.7,.2,1),filter .8s ease;}
.reveal.in{opacity:1;transform:none;filter:none;}
.serv-card.reveal:nth-child(2){transition-delay:.09s;}
.serv-card.reveal:nth-child(3){transition-delay:.18s;}
.proc-step.reveal:nth-child(2){transition-delay:.12s;}
.proc-step.reveal:nth-child(3){transition-delay:.24s;}
.proc-step.reveal:nth-child(4){transition-delay:.36s;}
.proc-step.reveal:nth-child(5){transition-delay:.48s;}
.port-card.reveal:nth-child(2){transition-delay:.08s;}
.port-card.reveal:nth-child(3){transition-delay:.16s;}

/* ---- responsivo ---- */
@media (max-width:980px){
  .ryz-links,.ryz-nav-cta{display:none;}
  .ryz-burger{display:flex;}
  .ryz-mobile{display:flex;}
  .ryz-hero{padding:116px 0 64px;}
  .ryz-hero-in{grid-template-columns:1fr;gap:54px;}
  .ryz-comp{order:2;min-height:0;}
  .quem-grid{grid-template-columns:1fr;gap:44px;}
  .quem-back{display:none;}
  .serv-grid{grid-template-columns:1fr;}
  .proc-line{grid-template-columns:repeat(2,1fr);gap:38px 26px;}
  .port-grid{grid-template-columns:repeat(2,1fr);}
  .porque-grid{grid-template-columns:1fr;}
  .porque-item:nth-child(odd){border-right:none;}
  .porque-text{max-width:none;}
  .ryz-bars.porque-watermark{display:none;}
  .faq-wrap{grid-template-columns:1fr;gap:34px;}
}
@media (max-width:560px){
  .ryz-sec{padding:80px 0;}
  .port-grid{grid-template-columns:1fr;}
  .proc-line{grid-template-columns:1fr;}
  .comp-card{width:100%;max-width:none;}
  .foot-in{flex-direction:column;gap:36px;}
}
@media (prefers-reduced-motion:reduce){
  .ryz-root *{animation:none!important;}
  .ryz-anim{opacity:1!important;transform:none!important;filter:none!important;}
  .reveal{opacity:1!important;transform:none!important;filter:none!important;transition:none!important;}
  .comp-card,.comp-back{transform:none!important;}
  .proc-step .proc-bars i{background:var(--green)!important;}
}
`;
